// // This module compares two 4-bit inputs, A and B, and produces three output signals: greater, less, and equal. On each rising edge of the clock, if the reset signal is asserted, all output signals are set to HIGH. When the reset is not active, the module evaluates the inputs A and B, setting greater to LOW if A is greater than B, less to LOW if A is less than B, and equal to LOW if both inputs are equal, ensuring only one of the output flags is LOW at any time.
module top_module(
  input clk,
  input reset,
  input [3:0] A,
  input [3:0] B,
  output reg greater,
  output reg less,
  output reg equal
);always @(posedge clk) begin
    if (reset) begin
      greater <= 0;
      less <= 0;
      equal <= 0;
    end
    else begin
      if (A > B) begin
        greater <= 1;
        less <= 0;
        equal <= 0;
      end
      else if (A < B) begin
        greater <= 0;
        less <= 1;
        equal <= 0;
      end
      else begin
        greater <= 0;
        less <= 0;
        equal <= 1;
      end
    end
  end

endmodule
